+            } else {
+              state_value = toFloat(rState_ptr[e]);
+            }
+            auto const B_value = toFloat(sram.B[i + e]);
+            auto const C_value = toFloat(sram.C[i + e]);
+            auto const dB = B_value * dt_value;
